            if arr[i] < arr[i - 1] {
                let mut j = i;
                while j > 0 && arr[j] < arr[j - 1] {
                    arr.swap(j, j - 1);
                    j -= 1;
                }
            }
        }
        return;
    }

    let mid = len / 2;
    if arr[mid] < arr[0] { arr.swap(mid, 0); }
    if arr[len - 1] < arr[0] { arr.swap(len - 1, 0); }
    if arr[len - 1] < arr[mid] { arr.swap(len - 1, mid); }

    arr.swap(mid, len - 1);
    let pivot = arr[len - 1].clone();
    let (mut i, mut j) = (0, len - 2);

    loop {
        while i < len - 1 && arr[i] < pivot { i += 1; }
        while j > 0 && arr[j] > pivot { j -= 1; }
        if i >= j { break; }
        arr.swap(i, j);
        i += 1;
        if j > 0 { j -= 1; }
    }

    arr.swap(i, len - 1);
    let (left, right) = arr.split_at_mut(i);
    adaptive_sort(left);
    adaptive_sort(&mut right[1..]);
}
